import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../context/AuthContext';
import { FaHome, FaPills, FaCalendarAlt, FaUser, FaCog, FaBars, FaTimes, FaStethoscope, FaClock } from 'react-icons/fa';

const Navbar = () => {
  const { t } = useTranslation();
  const { user, logout, isAuthenticated } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const navItems = [
    { path: '/', label: t('home'), icon: FaHome },
    { path: '/medicines', label: t('medicines'), icon: FaPills, requiresAuth: true },
    { path: '/availability', label: t('availability'), icon: FaClock },
    { path: '/schedule', label: t('schedule'), icon: FaCalendarAlt, requiresAuth: true },
    { path: '/profile', label: t('profile'), icon: FaUser, requiresAuth: true },
    { path: '/settings', label: t('settings'), icon: FaCog }
  ];

  // Filter nav items based on authentication status
  const visibleNavItems = navItems.filter(item => !item.requiresAuth || isAuthenticated);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  return (
    <nav className="fixed top-0 left-0 right-0 bg-white shadow-md z-50">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between h-16">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2 text-primary-color font-bold text-xl">
            <FaStethoscope className="text-2xl" />
            <span>MediCure</span>
          </Link>

          {/* Desktop Navigation - Removed */}
          <div className="hidden md:flex items-center gap-6">
            {/* Navigation removed - only logo remains */}
          </div>

          {/* User Menu - Removed */}
          <div className="hidden md:flex items-center gap-4">
            {/* Login/user menu removed */}
          </div>

          {/* Mobile menu button */}
          <button
            onClick={toggleMobileMenu}
            className="md:hidden p-2 rounded-lg text-gray-600 hover:text-primary-color hover:bg-gray-100"
          >
            {isMobileMenuOpen ? <FaTimes /> : <FaBars />}
          </button>
        </div>

        {/* Mobile Navigation */}
        {isMobileMenuOpen && (
          <div className="md:hidden border-t bg-white">
            <div className="py-4 space-y-2">
              {visibleNavItems.map((item) => {
                const Icon = item.icon;
                const isActive = location.pathname === item.path;
                
                return (
                  <Link
                    key={item.path}
                    to={item.path}
                    onClick={() => setIsMobileMenuOpen(false)}
                    className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                      isActive
                        ? 'bg-primary-light text-primary-color'
                        : 'text-gray-600 hover:text-primary-color hover:bg-gray-100'
                    }`}
                  >
                    <Icon className="text-lg" />
                    <span className="font-medium">{item.label}</span>
                  </Link>
                );
              })}
              
              {/* Mobile user info and actions */}
              <div className="border-t pt-4 mt-4">
                {isAuthenticated ? (
                  <>
                    <div className="px-4 py-2">
                      <div className="font-medium text-gray-900">{user?.name}</div>
                      <div className="text-sm text-gray-500 capitalize">{user?.user_type}</div>
                    </div>
                    <button
                      onClick={handleLogout}
                      className="w-full mt-2 mx-4 btn btn-outline"
                      style={{ width: 'calc(100% - 2rem)' }}
                    >
                      Logout
                    </button>
                  </>
                ) : (
                  <Link
                    to="/login"
                    onClick={() => setIsMobileMenuOpen(false)}
                    className="w-full mt-2 mx-4 btn btn-primary"
                    style={{ width: 'calc(100% - 2rem)' }}
                  >
                    Login
                  </Link>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
